  "npm/all/topology/app_name_session": "INJECT timepast\nOIDSET { oid:$oid, okind:$okind, onode:$onode}\nCATEGORY { \"npm_process_tag_data\":6h, \"npm_process_tag_data{m5}\":1d, \"npm_process_tag_data{h1}\":unlimit }\nTAGLOAD\nINJECT default\n\nSELECT [time, protocol, direction, app_name, local_ip, foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, session_count_logbits]\nUNFOLD [protocol, direction, app_name, local_ip, foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, session_count_logbits]\n\nJOIN {query:list, pk:[foreign_ip, foreign_port, foreign_pod_id, foreign_container_id]}\nUPDATE { key: \"foreign_app_name\", notnull: \"untagged\" }\nUPDATE { key: \"local_inbound_check\", notnull: 0 }\nFILTER { key: \"local_inbound_check\", value: 0 }\n\nCREATE { key: foreign_app_name, expr: \"local_ip == foreign_ip ? app_name : foreign_app_name\"}\nCREATE { key: _name_, expr: \"direction == 'OUT' ? app_name+'->'+foreign_app_name : foreign_app_name+'->'+app_name\"}\n\nGROUP { timeunit: 1h, user:'session_count_logbits', merge: [_name_], pk: [_name_] }\nRENAME {src : session_count_logbits, dst: session_count}\n\nSUB list\nCATEGORY npm_process_tag_list\nTAGLOAD {backward : true}\nSELECT [foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, foreign_app_name, local_inbound_check ]\nUNFOLD [foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, foreign_app_name, local_inbound_check ]\nFIRST-ONLY {key:['foreign_ip', 'foreign_port', 'foreign_pod_id', 'foreign_container_id']}\nLIMIT 1000\nEND\n\n",
  "npm/all/topology/appname_and_processtype": "INJECT timepast\nOIDSET { oid:$oid, okind:$okind, onode:$onode}\nCATEGORY { \"npm_process_tag_data\":6h, \"npm_process_tag_data{m5}\":1d, \"npm_process_tag_data{h1}\":unlimit }\nTAGLOAD\nINJECT default\n\nSELECT [time, protocol, direction, process_type, app_name, foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, tot_jitter, tot_latency,retransmission_count,send_packet_size,send_packet_count,recv_packet_size,recv_packet_count,lost_count, row_count, tcp_row_count, session_count_logbits]\nUNFOLD [protocol, direction, process_type, app_name, foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, tot_jitter, tot_latency,retransmission_count,send_packet_size,send_packet_count,recv_packet_size,recv_packet_count,lost_count, row_count, tcp_row_count, session_count_logbits]\n\nJOIN {query:list, pk:[foreign_ip, foreign_port, foreign_pod_id, foreign_container_id]}\n\nOIUPDATE { key: 'foreign_process_type', notnull: 'untagged' }\nUPDATE { key: 'foreign_app_name', notnull: 'untagged' }\nUPDATE { key: 'foreign_host_tag', notnull: 'untagged' }\nUPDATE { key: 'local_inbound_check', notnull: 0 }\n\nFILTER { key: \"local_inbound_check\", value: 0 }\n\nFILTER { key: \"foreign_process_type\", expr: \"foreign_process_type != 'InBound Check' && foreign_process_type != ''\" }\nFILTER { key: \"foreign_app_name\", expr: \"foreign_app_name!= 'InBound Check' && foreign_app_name != ''\" }\n\nCREATE { key: source_tag, expr: \"direction == 'OUT' ? app_name + ':' + process_type : foreign_app_name + ':' + foreign_process_type\"}\nCREATE { key: target_tag, expr: \"direction == 'OUT' ? foreign_app_name + ':' + foreign_process_type : app_name + ':' + process_type\"}\n\nCREATE { key: source_tag, expr: \"source_tag == 'untagged:untagged' ? 'untagged' : source_tag\"}\nCREATE { key: target_tag, expr: \"target_tag == 'untagged:untagged' ? 'untagged' : target_tag\"}\n\nCREATE { key: send_packet, expr: \"direction == 'OUT' ? send_packet_count : recv_packet_count \"}\nCREATE { key: send_byte, expr: \"direction == 'OUT' ? send_packet_size : recv_packet_size \"}\nCREATE { key: recv_packet, expr: \"direction == 'OUT' ? recv_packet_count : send_packet_count\"}\nCREATE { key: recv_byte, expr: \"direction == 'OUT' ? recv_packet_size : send_packet_size \"}\nRENAME {src : send_packet, dst: send_packet_count}\nRENAME {src : send_byte, dst: send_packet_size}\nRENAME {src : recv_packet, dst: recv_packet_count}\nRENAME {src : recv_byte, dst: recv_packet_size}\n\nCREATE { key:_id_, expr: \"source_tag + '_' + target_tag\" }\nCREATE { key:_name_, expr: \"source_tag + '->' + target_tag\" }\n\nCREATE { key: tcp_row_count, expr: \"protocol == 'TCP' ? row_count : 0\" }\n\nGROUP { timeunit: 1h, user:'session_count_logbits', merge:[tot_jitter, tot_latency,retransmission_count,send_packet_size,send_packet_count,recv_packet_size,recv_packet_count,lost_count, row_count, tcp_row_count], pk: [_id_, _name_] }\nRENAME {src : session_count_logbits, dst: session_count}\n\nUPDATE { key:'tot_jitter', value:sum }\nUPDATE { key:'tot_latency', value:sum }\nUPDATE { key:'retransmission_count', value:sum }\nUPDATE { key:'send_packet_size', value:sum }\nUPDATE { key:'send_packet_count', value:sum }\nUPDATE { key:'recv_packet_size', value:sum }\nUPDATE { key:'recv_packet_count', value:sum }\nUPDATE { key:'lost_count', value:sum }\nUPDATE { key:'row_count', value: sum }\nUPDATE { key:'tcp_row_count', value: sum }\n\nJOIN {query:row, pk:[_id_, _name_]}\n\nUPDATE { key: 'rows', notnull: 0 }\n\nCREATE { key: \"bps\", expr: \"(send_packet_size + recv_packet_size) / (60 * rows)\" }\nCREATE { key: \"pps\", expr: \"(send_packet_count + recv_packet_count) / (60 * rows)\" }\n\nCREATE { key: 'avg_jitter', expr: \"tot_jitter / tcp_row_count\" }\nCREATE { key: 'avg_latency', expr: \"tot_latency / tcp_row_count\" }\n\nSUB row\nOIDSET { oid:$oid, okind:$okind, onode:$onode}\nCATEGORY { \"npm_process_tag_data\":6h, \"npm_process_tag_data{m5}\":1d, \"npm_process_tag_data{h1}\":unlimit }\nTAGLOAD\n\nSELECT [time, direction, process_type, app_name, foreign_ip, foreign_port, foreign_pod_id, foreign_container_id]\nUNFOLD [direction, process_type, app_name, foreign_ip, foreign_port, foreign_pod_id, foreign_container_id]\n\nJOIN {query:list, pk:[foreign_ip, foreign_port, foreign_pod_id, foreign_container_id]}\n\nUPDATE { key: 'foreign_process_type', notnull: 'untagged' }\nUPDATE { key: 'foreign_app_name', notnull: 'untagged' }\nUPDATE { key: 'local_inbound_check', notnull: 0 }\n\nFILTER { key: \"local_inbound_check\", value: 0 }\n\nCREATE { key: 'foreign_process_type', expr: \"foreign_process_type != 0 ? foreign_process_type : 'untagged'\" }\nCREATE { key: 'foreign_app_name', expr: \"foreign_app_name!= 0 ? foreign_app_name: 'untagged'\" }\n\nFILTER { key: \"foreign_process_type\", expr: \"foreign_process_type != 'InBound Check' && foreign_process_type != ''\" }\nFILTER { key: \"foreign_app_name\", expr: \"foreign_app_name!= 'InBound Check' && foreign_app_name != ''\" }\n\nCREATE { key: source_tag, expr: \"direction == 'OUT' ? app_name + ':' + process_type : foreign_app_name + ':' + foreign_process_type\"}\nCREATE { key: target_tag, expr: \"direction == 'OUT' ? foreign_app_name + ':' + foreign_process_type : app_name + ':' + process_type\"}\n\nCREATE { key: source_tag, expr: \"source_tag == 'untagged:untagged' ? 'untagged' : source_tag\"}\nCREATE { key: target_tag, expr: \"target_tag == 'untagged:untagged' ? 'untagged' : target_tag\"}\n\nCREATE { key:_id_, expr: \"source_tag + '_' + target_tag\" }\nCREATE { key:_name_, expr: \"source_tag + '->' + target_tag\" }\n\nGROUP { timeunit:1m, pk: [_id_, _name_] }\nGROUP { timeunit:1d, pk: [_id_, _name_] }\nRENAME { src: _rows_, dst: rows }\nSELECT [_id_, _name_, rows]\nEND\n\nSUB list\nCATEGORY npm_process_tag_list\nTAGLOAD {backward : true}\nSELECT [foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, foreign_process_type, foreign_app_name, foreign_host_tag, local_inbound_check\t]\nUNFOLD [foreign_ip, foreign_port, foreign_pod_id, foreign_container_id, foreign_process_type, foreign_app_name, foreign_host_tag, local_inbound_check\t]\nFIRST-ONLY {key:['foreign_ip','foreign_port', 'foreign_pod_id', 'foreign_container_id']}\nLIMIT 1000\nEND\n\n",
